      insights.push({
        content: match[1].trim(),
        checkpointId: checkpoint.checkpoint_id,
        commitMessage: checkpoint.commit_message,
        commitSha: checkpoint.commit_sha,
        timestamp: msg.timestamp,
      });
    }
  }

  return insights;
}

