177→#[derive(serde::Serialize)]
178→struct FileDiff {
179→    path: String,
180→    status: String, // "added", "modified", "deleted"
181→    hunks: Vec<DiffHunk>,
182→}
183→
184→#[derive(serde::Serialize)]
185→struct DiffHunk {
186→    header: String,
187→    lines: Vec<DiffLine>,
188→}
189→
190→#[derive(serde::Serialize)]
191→struct DiffLine {
192→    kind: String, // "add", "delete", "context"
193→    content: String,
194→    old_lineno: Option<u32>,
195→    new_lineno: Option<u32>,
196→}
197→
198→/// Convert a git2::Diff into our FileDiff structs
199→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
200→    let mut files: Vec<FileDiff> = Vec::new();
201→
202→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
203→        let path = delta
204→            .new_file()
205→            .path()
206→            .or_else(|| delta.old_file().path())
207→            .map(|p| p.to_string_lossy().to_string())
208→            .unwrap_or_default();
209→
210→        let status = match delta.status() {
211→            git2::Delta::Added => "added",
212→            git2::Delta::Deleted => "deleted",
213→            _ => "modified",
214→        };
215→
216→        // Ensure we have a FileDiff entry for this path
217→        if files.last().map_or(true, |f| f.path != path) {
218→            files.push(FileDiff {
219→                path: path.clone(),
220→                status: status.to_string(),
221→                hunks: Vec::new(),
222→            });
223→        }
224→
225→        let file = files.last_mut().unwrap();
226→
227→        // New hunk
228→        if let Some(h) = hunk {
229→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
230→            if file.hunks.last().map_or(true, |last| last.header != header) {
231→                file.hunks.push(DiffHunk {
232→                    header,
233→                    lines: Vec::new(),
234→                });
235→            }
236→        }
237→
238→        // Diff line
239→        if let Some(current_hunk) = file.hunks.last_mut() {
240→            let kind = match line.origin() {
241→                '+' => "add",
242→                '-' => "delete",
243→                ' ' => "context",
244→                _ => return true,
245→            };
246→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
247→            current_hunk.lines.push(DiffLine {
248→                kind: kind.to_string(),
249→                content,
250→                old_lineno: line.old_lineno(),
251→                new_lineno: line.new_lineno(),
252→            });
253→        }
254→
255→        true
256→    })
257→    .map_err(|e| format!("Failed to print diff: {}", e))?;
258→
259→    Ok(files)
260→}
261→
262→#[tauri::command]
263→fn get_checkpoint_diff(
264→    repo_path: String,
265→    commit_sha: String,
266→) -> Result<Vec<FileDiff>, String> {
267→    if commit_sha.is_empty() {
268→        return Err("No commit SHA available for this checkpoint".to_string());
269→    }
270→
271→    let repo = git::open_repo(&repo_path)?;
272→    let oid = git2::Oid::from_str(&commit_sha)
273→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
274→    let commit = repo
275→        .find_commit(oid)
276→        .map_err(|e| format!("Commit not found: {}", e))?;
277→
278→    let tree = commit
279→        .tree()
280→        .map_err(|e| format!("Failed to get tree: {}", e))?;
281→
282→    // Diff against parent (or empty tree if no parent)
283→    let parent_tree = commit
284→        .parent(0)
285→        .ok()
286→        .and_then(|p| p.tree().ok());
287→
288→    let diff = repo
289→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
290→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
291→
292→    collect_diff_files(&diff)
293→}
294→
295→#[tauri::command]
296→fn get_branch_diff(
297→    repo_path: String,
298→    branch: String,
299→) -> Result<Vec<FileDiff>, String> {
300→    let repo = git::open_repo(&repo_path)?;
301→
302→    // Resolve the branch HEAD
303→    let branch_ref = repo
304→        .find_branch(&branch, git2::BranchType::Local)
305→        .map_err(|e| format!("Branch not found: {}", e))?;
306→    let branch_commit = branch_ref
307→        .get()
308→        .peel_to_commit()
309→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
310→
311→    // Find the default branch (try main, then master)
312→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
313→        "main"
314→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
315→        "master"
316→    } else {
317→        return Err("No default branch (main/master) found".to_string());
318→    };
319→
320→    // If we're diffing the default branch against itself, return empty
321→    if branch == default_branch_name {
322→        return Ok(Vec::new());
323→    }
324→
325→    let default_ref = repo
326→        .find_branch(default_branch_name, git2::BranchType::Local)
327→        .map_err(|e| format!("Default branch error: {}", e))?;
328→    let default_commit = default_ref
329→        .get()
330→        .peel_to_commit()
331→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
332→
333→    // Find merge base
334→    let merge_base_oid = repo
335→        .merge_base(default_commit.id(), branch_commit.id())
336→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
337→    let merge_base_commit = repo
338→        .find_commit(merge_base_oid)
339→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
340→
341→    let base_tree = merge_base_commit
342→        .tree()
343→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
344→    let branch_tree = branch_commit
345→        .tree()
346→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
347→
348→    let diff = repo
349→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
350→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
351→
352→    collect_diff_files(&diff)
353→}
