 87→/// List all checkpoints from the entire/checkpoints/v1 branch
 88→pub fn list_checkpoints(
 89→    repo: &Repository,
 90→    filter_branch: &str,
 91→) -> Result<Vec<CheckpointSummary>, String> {
 92→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 93→        Ok(b) => b,
 94→        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 95→    };
 96→
 97→    let commit = branch_ref
 98→        .get()
 99→        .peel_to_commit()
100→        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
101→
102→    let tree = commit
103→        .tree()
104→        .map_err(|e| format!("Failed to get tree: {}", e))?;
105→
106→    let mut checkpoints = Vec::new();
107→
108→    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
109→    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
110→        let name = match entry.name() {
111→            Some(n) => n,
112→            None => return git2::TreeWalkResult::Ok,
113→        };
114→
115→        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
116→        if name == "metadata.json" && !dir.is_empty() {
117→            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
118→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
119→            if parts.len() == 2 {
120→                // This is a root checkpoint metadata.json
121→                if let Ok(blob) = repo.find_blob(entry.id()) {
122→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
123→                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
124→                            let branch = meta.branch.clone().unwrap_or_default();
125→                            if filter_branch.is_empty() || branch == filter_branch {
126→                                let cp = build_checkpoint_summary(
127→                                    repo,
128→                                    &tree,
129→                                    dir,
130→                                    &meta,
131→                                );
132→                                if let Ok(cp) = cp {
133→                                    checkpoints.push(cp);
134→                                }
135→                            }
136→                        }
137→                    }
138→                }
139→            }
140→        }
141→
142→        git2::TreeWalkResult::Ok
143→    })
144→    .map_err(|e| format!("Tree walk error: {}", e))?;
145→
146→    // Sort by created_at descending
147→    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
148→
149→    Ok(checkpoints)
150→}
