234→/// Find the most recent commit on a branch at or before the given timestamp.
235→/// Returns (sha, message) or None if not found.
236→fn resolve_commit_from_branch(
237→    repo: &Repository,
238→    branch_name: &str,
239→    created_at: &str,
240→) -> Option<(String, String)> {
241→    if branch_name.is_empty() || created_at.is_empty() {
242→        return None;
243→    }
244→
245→    let branch = repo.find_branch(branch_name, git2::BranchType::Local).ok()?;
246→    let branch_commit = branch.get().peel_to_commit().ok()?;
247→
248→    // Parse the checkpoint created_at as a unix timestamp for comparison
249→    let checkpoint_ts = parse_iso_timestamp(created_at)?;
250→
251→    // Walk commits from branch HEAD backward
252→    let mut revwalk = repo.revwalk().ok()?;
253→    revwalk.push(branch_commit.id()).ok()?;
254→    revwalk.set_sorting(git2::Sort::TIME).ok()?;
255→
256→    for oid in revwalk {
257→        let oid = oid.ok()?;
258→        let commit = repo.find_commit(oid).ok()?;
259→        let commit_ts = commit.time().seconds();
260→
261→        // Find the first commit whose time is at or before the checkpoint
262→        if commit_ts <= checkpoint_ts {
263→            let sha = oid.to_string();
264→            let message = commit
265→                .summary()
266→                .unwrap_or("")
267→                .to_string();
268→            return Some((sha, message));
269→        }
270→    }
271→
272→    None
273→}
274→
275→/// Parse an ISO 8601 timestamp string to unix seconds
276→fn parse_iso_timestamp(s: &str) -> Option<i64> {
277→    // Handle formats like "2026-03-16T21:10:30.808196Z" and "2026-03-16T21:10:30Z"
278→    let s = s.trim();
279→    // Strip fractional seconds and Z
280→    let s = s.trim_end_matches('Z');
281→    let s = if let Some(dot_pos) = s.rfind('.') {
282→        &s[..dot_pos]
283→    } else {
284→        s
285→    };
286→
287→    // Parse "YYYY-MM-DDTHH:MM:SS"
288→    let parts: Vec<&str> = s.split('T').collect();
289→    if parts.len() != 2 {
290→        return None;
291→    }
292→    let date_parts: Vec<i64> = parts[0].split('-').filter_map(|p| p.parse().ok()).collect();
293→    let time_parts: Vec<i64> = parts[1].split(':').filter_map(|p| p.parse().ok()).collect();
294→
295→    if date_parts.len() != 3 || time_parts.len() != 3 {
296→        return None;
297→    }
298→
299→    let (year, month, day) = (date_parts[0], date_parts[1], date_parts[2]);
300→    let (hour, min, sec) = (time_parts[0], time_parts[1], time_parts[2]);
301→
302→    // Simple days-since-epoch calculation (good enough for comparison)
303→    let mut days: i64 = 0;
304→    for y in 1970..year {
305→        days += if y % 4 == 0 && (y % 100 != 0 || y % 400 == 0) { 366 } else { 365 };
306→    }
307→    let month_days = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
308→    let is_leap = year % 4 == 0 && (year % 100 != 0 || year % 400 == 0);
309→    for m in 1..month {
310→        days += month_days[m as usize];
311→        if m == 2 && is_leap {
312→            days += 1;
313→        }
314→    }
315→    days += day - 1;
316→
317→    Some(days * 86400 + hour * 3600 + min * 60 + sec)
318→}
