320→fn count_transcript_steps(
321→    repo: &Repository,
322→    session_ref: &RawSessionRef,
323→    session_dir: &str,
324→) -> u32 {
325→    // Try to read the transcript file and count assistant messages (steps)
326→    // Paths from metadata may be absolute (leading /) — use as-is, stripping the /
327→    let transcript_path = session_ref
328→        .transcript
329→        .as_deref()
330→        .map(|t| {
331→            if t.starts_with('/') {
332→                t.trim_start_matches('/').to_string()
333→            } else {
334→                format!("{}{}", session_dir, t)
335→            }
336→        })
337→        .unwrap_or_else(|| format!("{}full.jsonl", session_dir));
338→
339→    if let Ok(content) = read_blob_from_tree(repo, &transcript_path) {
340→        content
341→            .lines()
342→            .filter(|line| line.contains("\"role\":\"assistant\"") || line.contains("\"role\": \"assistant\""))
343→            .count() as u32
344→    } else {
345→        0
346→    }
347→}
348→
349→fn read_blob_from_tree(repo: &Repository, path: &str) -> Result<String, String> {
350→    let branch_ref = repo
351→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
352→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
353→
354→    let commit = branch_ref
355→        .get()
356→        .peel_to_commit()
357→        .map_err(|e| format!("Failed to peel: {}", e))?;
358→
359→    let tree = commit
360→        .tree()
361→        .map_err(|e| format!("Failed to get tree: {}", e))?;
362→
363→    let entry = tree
364→        .get_path(std::path::Path::new(path))
365→        .map_err(|e| format!("Path not found: {}", e))?;
366→
367→    let blob = repo
368→        .find_blob(entry.id())
369→        .map_err(|e| format!("Failed to read blob: {}", e))?;
370→
371→    std::str::from_utf8(blob.content())
372→        .map(|s| s.to_string())
373→        .map_err(|e| format!("Invalid UTF-8: {}", e))
374→}
