 27→pub fn open_repo(path: &str) -> Result<Repository, String> {
 28→    Repository::open(path).map_err(|e| format!("Failed to open repo: {}", e))
 29→}
 30→
 31→pub fn list_branches(repo: &Repository) -> Result<Vec<BranchInfo>, String> {
 32→    let mut branches = Vec::new();
 33→    let head = repo.head().ok();
 34→    let head_name = head
 35→        .as_ref()
 36→        .and_then(|h| h.shorthand().map(|s| s.to_string()));
 37→
 38→    let git_branches = repo
 39→        .branches(Some(git2::BranchType::Local))
 40→        .map_err(|e| format!("Failed to list branches: {}", e))?;
 41→
 42→    for branch_result in git_branches {
 43→        let (branch, _) = branch_result.map_err(|e| format!("Branch error: {}", e))?;
 44→        if let Some(name) = branch.name().ok().flatten() {
 45→            // Skip entire/ internal branches
 46→            if name.starts_with("entire/") {
 47→                continue;
 48→            }
 49→            branches.push(BranchInfo {
 50→                is_head: head_name.as_deref() == Some(name),
 51→                name: name.to_string(),
 52→                checkpoint_count: 0, // TODO: count from checkpoint branch
 53→            });
 54→        }
 55→    }
 56→
 57→    Ok(branches)
 58→}
 59→
 60→pub fn list_worktrees(repo: &Repository) -> Result<Vec<WorktreeInfo>, String> {
 61→    let mut worktrees = Vec::new();
 62→    let wt_names = repo
 63→        .worktrees()
 64→        .map_err(|e| format!("Failed to list worktrees: {}", e))?;
 65→
 66→    for name in wt_names.iter() {
 67→        if let Some(name) = name {
 68→            if let Ok(wt) = repo.find_worktree(name) {
 69→                let wt_path = wt.path().to_string_lossy().to_string();
 70→                // Try to detect branch from worktree
 71→                let branch = detect_worktree_branch(&wt_path).unwrap_or_else(|| name.to_string());
 72→                worktrees.push(WorktreeInfo {
 73→                    path: wt_path,
 74→                    branch,
 75→                    is_main: false,
 76→                });
 77→            }
 78→        }
 79→    }
 80→
 81→    Ok(worktrees)
 82→}
 83→
 84→fn detect_worktree_branch(wt_path: &str) -> Option<String> {
 85→    let head_path = Path::new(wt_path).join(".git");
 86→    // Worktree .git is a file pointing to the main repo's worktree dir
 87→    if head_path.is_file() {
 88→        if let Ok(repo) = Repository::open(wt_path) {
 89→            if let Ok(head) = repo.head() {
 90→                return head.shorthand().map(|s| s.to_string());
 91→            }
 92→        }
 93→    }
 94→    None
 95→}
 96→
 97→pub fn get_repo_info(path: &str) -> Result<RepoInfo, String> {
 98→    let repo = open_repo(path)?;
 99→    let name = Path::new(path)
100→        .file_name()
101→        .map(|n| n.to_string_lossy().to_string())
102→        .unwrap_or_else(|| "unknown".to_string());
103→
104→    let mut branches = list_branches(&repo)?;
105→    let worktrees = list_worktrees(&repo)?;
106→
107→    // Count checkpoints per branch from the checkpoint tree
108→    let counts = count_checkpoints_per_branch(&repo);
109→    for branch in &mut branches {
110→        if let Some(&count) = counts.get(&branch.name) {
111→            branch.checkpoint_count = count;
112→        }
113→    }
114→
115→    Ok(RepoInfo {
116→        path: path.to_string(),
117→        name,
118→        branches,
119→        worktrees,
120→    })
121→}
122→
123→/// Count checkpoints per branch by walking the checkpoint tree
124→fn count_checkpoints_per_branch(repo: &Repository) -> std::collections::HashMap<String, u32> {
125→    let mut counts = std::collections::HashMap::new();
126→
127→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
128→        Ok(b) => b,
129→        Err(_) => return counts,
130→    };
131→
132→    let commit = match branch_ref.get().peel_to_commit() {
133→        Ok(c) => c,
134→        Err(_) => return counts,
135→    };
136→
137→    let tree = match commit.tree() {
138→        Ok(t) => t,
139→        Err(_) => return counts,
140→    };
141→
142→    let _ = tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
143→        let name = match entry.name() {
144→            Some(n) => n,
145→            None => return git2::TreeWalkResult::Ok,
146→        };
147→
148→        if name == "metadata.json" && !dir.is_empty() {
149→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
150→            if parts.len() == 2 {
151→                if let Ok(blob) = repo.find_blob(entry.id()) {
152→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
153→                        // Quick parse just the branch field
154→                        if let Ok(val) = serde_json::from_str::<serde_json::Value>(content) {
155→                            if let Some(branch) = val.get("branch").and_then(|b| b.as_str()) {
156→                                *counts.entry(branch.to_string()).or_insert(0) += 1;
157→                            }
158→                        }
159→                    }
160→                }
161→            }
162→        }
163→
164→        git2::TreeWalkResult::Ok
165→    });
166→
167→    counts
168→}
