 38→  );
 39→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 40→    () => localStorage.getItem("entire:terminal-open") !== "false"
 41→  );
 42→  const [innerTab, setInnerTab] = useState<
 43→    "checkpoints" | "diff" | "insights"
 44→  >("checkpoints");
 45→  const [selectedCheckpoint, setSelectedCheckpoint] =
 46→    useState<CheckpointSummary | null>(null);
 47→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 48→    "transcript" | "diff" | "insights"
 49→  >("transcript");
 50→
 51→  // Per-branch terminal sessions
 52→  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
 53→    () => new Map()
 54→  );
 55→
 56→  const terminalRef = useRef<TerminalPanelHandle>(null);
 57→
 58→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 59→  const activeSession = sessionMap.get(activeTabId) ?? null;
 60→
 61→  // Live updates — watch active repo for checkpoint/session changes
 62→  useLiveUpdates(activeTab.repoPath);
 63→
 64→  const handleSessionChange = useCallback(
 65→    (session: TermSession | null) => {
 66→      setSessionMap((prev) => {
 67→        const next = new Map(prev);
 68→        if (session) {
 69→          next.set(activeTabId, session);
 70→        } else {
 71→          next.delete(activeTabId);
 72→        }
 73→        return next;
 74→      });
 75→    },
 76→    [activeTabId]
 77→  );
 78→
 79→  // Agent dispatch — launch external Ghostty window
