 81→    (agent: string, prompt: string) => {
 82→      invoke("launch_ghostty_agent", {
 83→        repoPath: activeTab.repoPath,
 84→        agent,
 85→        prompt,
 86→      }).catch((err: unknown) => {
 87→        console.error("Failed to launch external agent:", err);
 88→        // Fallback: open in embedded terminal
 89→        if (!isTerminalOpen) setIsTerminalOpen(true);
 90→        setTimeout(() => {
 91→          terminalRef.current?.launchAgentWithPrompt(agent, prompt);
 92→        }, isTerminalOpen ? 0 : 100);
 93→      });
 94→    },
 95→    [activeTab.repoPath, isTerminalOpen]
 96→  );
 97→
 98→  // Persist UI state to localStorage
 99→  useEffect(() => {
100→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
101→  }, [terminalHeight]);
102→  useEffect(() => {
103→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
104→  }, [isTerminalOpen]);
105→
106→  // Clear selected checkpoint when switching branch tabs
107→  useEffect(() => {
108→    setSelectedCheckpoint(null);
109→    setCheckpointInnerTab("transcript");
110→  }, [activeTabId]);
111→
112→  // Keyboard shortcuts
113→  useEffect(() => {
114→    function onKeyDown(e: KeyboardEvent) {
115→      const meta = e.metaKey || e.ctrlKey;
116→
117→      // Cmd+K = focus search
118→      if (meta && e.key === "k") {
119→        e.preventDefault();
120→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
121→      }
122→      // Ctrl+` = toggle terminal
123→      if (e.ctrlKey && e.key === "`") {
124→        e.preventDefault();
125→        setIsTerminalOpen((v) => !v);
126→      }
127→      // Cmd+W = close active tab
128→      if (meta && e.key === "w") {
129→        e.preventDefault();
130→        handleCloseTab(activeTabId);
131→      }
132→      // Cmd+1-9 = switch to tab by index
133→      if (meta && e.key >= "1" && e.key <= "9") {
134→        e.preventDefault();
135→        const idx = parseInt(e.key) - 1;
136→        if (idx < tabs.length) {
137→          setActiveTabId(tabs[idx].id);
138→        }
139→      }
140→      // Cmd+[ / Cmd+] = prev/next tab
141→      if (meta && e.key === "[") {
142→        e.preventDefault();
143→        const idx = tabs.findIndex((t) => t.id === activeTabId);
144→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
145→      }
146→      if (meta && e.key === "]") {
147→        e.preventDefault();
148→        const idx = tabs.findIndex((t) => t.id === activeTabId);
149→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
150→      }
151→      // Escape = deselect checkpoint
152→      if (e.key === "Escape" && selectedCheckpoint) {
153→        setSelectedCheckpoint(null);
154→      }
