 1→import { useQuery, useQueries } from "@tanstack/react-query";
 2→import { invoke } from "@tauri-apps/api/core";
 3→import type { RepoInfo, CheckpointSummary, TranscriptMessage, FileDiff } from "../lib/ipc";
 4→
 5→export function useReposQuery() {
 6→  return useQuery<RepoInfo[]>({
 7→    queryKey: ["repos"],
 8→    queryFn: () => invoke("list_repos"),
 9→    retry: false,
10→  });
11→}
12→
13→export function useCheckpointsQuery(repoPath: string, branch: string) {
14→  return useQuery<CheckpointSummary[]>({
15→    queryKey: ["checkpoints", repoPath, branch],
16→    queryFn: () => invoke("list_checkpoints", { repoPath, branch }),
17→    enabled: !!repoPath,
18→    retry: false,
19→  });
20→}
21→
22→export function useTranscriptQuery(
23→  repoPath: string,
24→  checkpointId: string,
25→  sessionIndex: number
26→) {
27→  return useQuery<TranscriptMessage[]>({
28→    queryKey: ["transcript", repoPath, checkpointId, sessionIndex],
29→    queryFn: () =>
30→      invoke("get_transcript", { repoPath, checkpointId, sessionIndex }),
31→    enabled: !!repoPath && !!checkpointId,
32→    retry: false,
33→  });
34→}
35→
36→export function useDiffQuery(repoPath: string, commitSha: string) {
37→  return useQuery<FileDiff[]>({
38→    queryKey: ["diff", repoPath, commitSha],
39→    queryFn: () => invoke("get_checkpoint_diff", { repoPath, commitSha }),
40→    enabled: !!repoPath && !!commitSha,
41→    retry: false,
42→  });
43→}
44→
45→export function useBranchDiffQuery(repoPath: string, branch: string) {
46→  return useQuery<FileDiff[]>({
47→    queryKey: ["branch-diff", repoPath, branch],
48→    queryFn: () => invoke("get_branch_diff", { repoPath, branch }),
49→    enabled: !!repoPath && !!branch,
50→    retry: false,
51→  });
52→}
53→
54→export function useBranchTranscriptsQuery(
55→  repoPath: string,
56→  branch: string,
57→  enabled: boolean
58→) {
59→  const { data: checkpoints } = useCheckpointsQuery(repoPath, branch);
60→
61→  const queries = useQueries({
62→    queries: (checkpoints ?? []).map((cp) => ({
63→      queryKey: ["transcript", repoPath, cp.checkpoint_id, 0] as const,
64→      queryFn: () =>
65→        invoke<TranscriptMessage[]>("get_transcript", {
66→          repoPath,
67→          checkpointId: cp.checkpoint_id,
68→          sessionIndex: 0,
69→        }),
70→      enabled: enabled && !!repoPath && !!cp.checkpoint_id,
71→      retry: false,
72→    })),
73→  });
74→
75→  return { checkpoints: checkpoints ?? [], queries };
76→}
