 1→use notify::RecursiveMode;
 2→use notify_debouncer_mini::{new_debouncer, DebouncedEventKind};
 3→use std::path::Path;
 4→use std::sync::mpsc;
 5→use std::time::Duration;
 6→
 7→#[allow(dead_code)]
 8→pub struct FileWatcher {
 9→    _watcher: notify::RecommendedWatcher,
10→}
11→
12→pub enum WatchEvent {
13→    CheckpointChanged,
14→    SessionChanged(#[allow(dead_code)] String),
15→    ConfigChanged,
16→}
17→
18→/// Start watching a repo for Entire-related file changes
19→pub fn watch_repo(
20→    repo_path: &str,
21→    callback: impl Fn(WatchEvent) + Send + 'static,
22→) -> Result<(), String> {
23→    let git_dir = Path::new(repo_path).join(".git");
24→    let entire_dir = Path::new(repo_path).join(".entire");
25→
26→    let (tx, rx) = mpsc::channel();
27→
28→    let mut debouncer = new_debouncer(Duration::from_millis(500), tx)
29→        .map_err(|e| format!("Failed to create debouncer: {}", e))?;
30→
31→    // Watch session directory
32→    let sessions_dir = git_dir.join("entire-sessions");
33→    if sessions_dir.exists() {
34→        debouncer
35→            .watcher()
36→            .watch(&sessions_dir, RecursiveMode::NonRecursive)
37→            .map_err(|e| format!("Failed to watch sessions: {}", e))?;
38→    }
39→
40→    // Watch .entire/ config directory
41→    if entire_dir.exists() {
42→        debouncer
43→            .watcher()
44→            .watch(&entire_dir, RecursiveMode::NonRecursive)
45→            .map_err(|e| format!("Failed to watch .entire: {}", e))?;
46→    }
47→
48→    // Watch git refs for checkpoint branch changes
49→    let refs_dir = git_dir.join("refs/heads/entire");
50→    if refs_dir.exists() {
51→        debouncer
52→            .watcher()
53→            .watch(&refs_dir, RecursiveMode::Recursive)
54→            .map_err(|e| format!("Failed to watch refs: {}", e))?;
55→    }
56→
57→    // Spawn thread to process events
58→    std::thread::spawn(move || {
59→        let _debouncer = debouncer; // Keep alive
60→        for result in rx {
61→            match result {
62→                Ok(events) => {
63→                    for event in events {
64→                        if event.kind == DebouncedEventKind::Any {
65→                            let path_str = event.path.to_string_lossy();
66→                            if path_str.contains("entire-sessions") {
67→                                callback(WatchEvent::SessionChanged(
68→                                    event.path.to_string_lossy().to_string(),
69→                                ));
70→                            } else if path_str.contains("refs/heads/entire/checkpoints") {
71→                                callback(WatchEvent::CheckpointChanged);
72→                            } else if path_str.contains(".entire") {
73→                                callback(WatchEvent::ConfigChanged);
74→                            }
75→                        }
76→                    }
77→                }
78→                Err(e) => {
79→                    eprintln!("Watch error: {:?}", e);
80→                }
81→            }
82→        }
83→    });
84→
85→    Ok(())
86→}
