143→function FileEntry({
144→  file,
145→  defaultExpanded,
146→  commentsByLine,
147→  activeCommentLine,
148→  onCommentClick,
149→  onSaveComment,
150→  onUpdateComment,
151→  onDeleteComment,
152→  onCloseComment,
153→}: {
154→  file: FileDiff;
155→  defaultExpanded: boolean;
156→  commentsByLine: Map<string, DiffComment[]>;
157→  activeCommentLine: string | null;
158→  onCommentClick: (
159→    lineKey: string,
160→    lineContent: string,
161→    lineNumber: number,
162→    lineKind: "add" | "delete" | "context"
163→  ) => void;
164→  onSaveComment: (
165→    filePath: string,
166→    lineKey: string,
167→    lineKind: "add" | "delete" | "context",
168→    lineContent: string,
169→    lineNumber: number,
170→    comment: string
171→  ) => void;
172→  onUpdateComment: (id: string, comment: string) => void;
173→  onDeleteComment: (id: string) => void;
174→  onCloseComment: () => void;
175→}) {
176→  const [expanded, setExpanded] = useState(defaultExpanded);
177→  const config = STATUS_CONFIG[file.status] || STATUS_CONFIG.modified;
178→  const Icon = config.icon;
179→
180→  const additions = file.hunks.reduce(
181→    (sum, h) => sum + h.lines.filter((l) => l.kind === "add").length,
182→    0
183→  );
184→  const deletions = file.hunks.reduce(
185→    (sum, h) => sum + h.lines.filter((l) => l.kind === "delete").length,
186→    0
187→  );
188→
189→  // Count comments for this file
190→  const fileCommentCount = Array.from(commentsByLine.entries()).reduce(
191→    (sum, [key, cs]) => (key.startsWith(file.path + ":") ? sum + cs.length : sum),
192→    0
193→  );
194→
195→  return (
196→    <div className="mb-2 overflow-hidden rounded-lg border border-border-subtle">
197→      {/* File header */}
198→      <button
199→        onClick={() => setExpanded(!expanded)}
200→        className="flex w-full items-center gap-2 bg-bg-overlay px-3 py-2 text-left transition-colors hover:bg-bg-hover"
201→      >
202→        {expanded ? (
203→          <ChevronDown size={14} className="shrink-0 text-fg-subtle" />
204→        ) : (
205→          <ChevronRight size={14} className="shrink-0 text-fg-subtle" />
206→        )}
207→        <Icon size={14} className={`shrink-0 ${config.color}`} />
208→        <span className="min-w-0 flex-1 truncate font-mono text-xs text-fg">
209→          {file.path}
210→        </span>
211→        {fileCommentCount > 0 && (
212→          <span
213→            className="flex h-4 min-w-[16px] shrink-0 items-center justify-center rounded-full px-1 text-[10px] font-medium text-white"
214→            style={{ backgroundColor: "var(--color-accent)" }}
215→          >
216→            {fileCommentCount}
217→          </span>
218→        )}
219→        <span className={`shrink-0 rounded px-1.5 py-0.5 text-[10px] font-medium ${config.bg} ${config.color}`}>
220→          {config.label}
221→        </span>
222→        {additions > 0 && (
223→          <span className="shrink-0 font-mono text-[11px] text-green">
224→            +{additions}
225→          </span>
226→        )}
227→        {deletions > 0 && (
228→          <span className="shrink-0 font-mono text-[11px] text-red">
229→            -{deletions}
230→          </span>
231→        )}
232→      </button>
233→
234→      {/* Diff hunks */}
235→      {expanded && (
236→        <div className="overflow-x-auto border-t border-border-subtle bg-bg">
237→          {file.hunks.map((hunk, hi) => (
238→            <div key={hi}>
239→              {/* Hunk header */}
240→              <div
241→                className="border-b px-4 py-1 font-mono text-[11px]"
242→                style={{
243→                  backgroundColor: "var(--color-diff-hunk-bg)",
244→                  borderColor: "var(--color-border-subtle)",
245→                  color: "var(--color-accent-fg)",
246→                }}
247→              >
248→                {hunk.header.trim()}
249→              </div>
250→              {/* Lines */}
251→              <div>
252→                {hunk.lines.map((line, li) => {
253→                  const lineKey = makeLineKey(file.path, line);
254→                  const lineComments = commentsByLine.get(lineKey) ?? [];
255→                  const isActive = activeCommentLine === lineKey;
256→
257→                  return (
258→                    <div key={li}>
259→                      <DiffLineRow
260→                        line={line}
261→                        lineKey={lineKey}
262→                        commentCount={lineComments.length}
263→                        onCommentClick={onCommentClick}
264→                      />
265→                      {/* Show comment box if line has comments or is active target */}
266→                      {(lineComments.length > 0 || isActive) && (
267→                        <DiffCommentBox
268→                          comments={lineComments}
269→                          filePath={file.path}
270→                          lineKey={lineKey}
271→                          lineKind={line.kind}
272→                          lineContent={line.content}
273→                          lineNumber={getLineNumber(line)}
274→                          onSave={onSaveComment}
275→                          onUpdate={onUpdateComment}
276→                          onDelete={onDeleteComment}
277→                          onClose={onCloseComment}
278→                        />
279→                      )}
280→                    </div>
281→                  );
282→                })}
283→              </div>
284→            </div>
285→          ))}
286→          {file.hunks.length === 0 && (
287→            <div className="px-4 py-3 text-xs text-fg-subtle">
288→              Binary file or no textual changes
289→            </div>
290→          )}
291→        </div>
292→      )}
293→    </div>
294→  );
295→}
