297→function DiffFileList({
298→  files,
299→  summaryLabel,
300→  summaryDetail,
301→  storageKey,
302→  context,
303→  onSendToAgent,
304→}: {
305→  files: FileDiff[];
306→  summaryLabel: string;
307→  summaryDetail?: string;
308→  storageKey: string;
309→  context: { commitSha?: string; branch?: string };
310→  onSendToAgent?: (agent: string, prompt: string) => void;
311→}) {
312→  const {
313→    comments,
314→    commentsByLine,
315→    addComment,
316→    updateComment,
317→    deleteComment,
318→    clearAll,
319→  } = useDiffComments(storageKey);
320→
321→  const [activeCommentLine, setActiveCommentLine] = useState<string | null>(
322→    null
323→  );
324→
325→  const totalAdditions = files.reduce(
326→    (sum, f) =>
327→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "add").length, 0),
328→    0
329→  );
330→  const totalDeletions = files.reduce(
331→    (sum, f) =>
332→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "delete").length, 0),
333→    0
334→  );
335→
336→  function handleCommentClick(
337→    lineKey: string,
338→    _lineContent: string,
339→    _lineNumber: number,
340→    _lineKind: "add" | "delete" | "context"
341→  ) {
342→    setActiveCommentLine((prev) => (prev === lineKey ? null : lineKey));
343→  }
344→
345→  function handleSaveComment(
346→    filePath: string,
347→    lineKey: string,
348→    lineKind: "add" | "delete" | "context",
349→    lineContent: string,
350→    lineNumber: number,
351→    comment: string
352→  ) {
353→    addComment(filePath, lineKey, lineKind, lineContent, lineNumber, comment);
354→    // Keep the comment box open after saving
355→  }
356→
357→  function handleCloseComment() {
358→    setActiveCommentLine(null);
359→  }
360→
361→  function handleSendToAgent(agent: string, prompt: string) {
362→    onSendToAgent?.(agent, prompt);
363→  }
364→
365→  return (
366→    <div className="relative flex flex-1 flex-col">
367→      <div className="flex-1 overflow-y-auto px-5 py-4">
