370→          <span className="font-mono text-xs text-fg-muted">{summaryLabel}</span>
371→          {summaryDetail && (
372→            <span className="text-xs text-fg-muted">{summaryDetail}</span>
373→          )}
374→          <div className="ml-auto flex items-center gap-3 text-xs">
375→            <span className="text-fg-subtle">{files.length} files</span>
376→            {totalAdditions > 0 && (
377→              <span className="font-mono text-green">+{totalAdditions}</span>
378→            )}
379→            {totalDeletions > 0 && (
380→              <span className="font-mono text-red">-{totalDeletions}</span>
381→            )}
382→          </div>
383→        </div>
384→        {files.map((file) => (
385→          <FileEntry
386→            key={file.path}
387→            file={file}
388→            defaultExpanded={files.length <= 5}
389→            commentsByLine={commentsByLine}
390→            activeCommentLine={activeCommentLine}
391→            onCommentClick={handleCommentClick}
392→            onSaveComment={handleSaveComment}
393→            onUpdateComment={updateComment}
394→            onDeleteComment={deleteComment}
395→            onCloseComment={handleCloseComment}
396→          />
397→        ))}
398→      </div>
399→
400→      {/* Review bar */}
401→      <ReviewBar
402→        comments={comments}
403→        context={context}
404→        onSendToAgent={handleSendToAgent}
405→        onClearAll={clearAll}
406→      />
407→    </div>
408→  );
409→}
