11→const INSIGHT_REGEX = /`?★\s*Insight\s*─+`?\s*\n([\s\S]*?)\n`?─{5,}`?/g;
12→
13→export function extractInsights(
14→  messages: TranscriptMessage[],
15→  checkpoint: CheckpointSummary
16→): Insight[] {
17→  const insights: Insight[] = [];
18→
19→  for (const msg of messages) {
20→    if (msg.role !== "assistant") continue;
21→
22→    let match: RegExpExecArray | null;
23→    INSIGHT_REGEX.lastIndex = 0;
24→    while ((match = INSIGHT_REGEX.exec(msg.content)) !== null) {
25→      insights.push({
26→        content: match[1].trim(),
27→        checkpointId: checkpoint.checkpoint_id,
28→        commitMessage: checkpoint.commit_message,
29→        commitSha: checkpoint.commit_sha,
30→        timestamp: msg.timestamp,
31→      });
32→    }
33→  }
34→
35→  return insights;
36→}
