54→export function useBranchTranscriptsQuery(
55→  repoPath: string,
56→  branch: string,
57→  enabled: boolean
58→) {
59→  const { data: checkpoints } = useCheckpointsQuery(repoPath, branch);
60→
61→  const queries = useQueries({
62→    queries: (checkpoints ?? []).map((cp) => ({
63→      queryKey: ["transcript", repoPath, cp.checkpoint_id, 0] as const,
64→      queryFn: () =>
65→        invoke<TranscriptMessage[]>("get_transcript", {
66→          repoPath,
67→          checkpointId: cp.checkpoint_id,
68→          sessionIndex: 0,
69→        }),
70→      enabled: enabled && !!repoPath && !!cp.checkpoint_id,
71→      retry: false,
72→    })),
73→  });
74→
75→  return { checkpoints: checkpoints ?? [], queries };
76→}
