 81→/// Read a blob from the entire/checkpoints/v1 branch by path
 82→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
 83→    let branch_ref = repo
 84→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
 85→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
 86→
 87→    let commit = branch_ref
 88→        .get()
 89→        .peel_to_commit()
 90→        .map_err(|e| format!("Failed to peel: {}", e))?;
 91→
 92→    let tree = commit
 93→        .tree()
 94→        .map_err(|e| format!("Failed to get tree: {}", e))?;
 95→
 96→    let entry = tree
 97→        .get_path(std::path::Path::new(path))
 98→        .map_err(|e| format!("Path not found: {}", e))?;
 99→
100→    let blob = repo
101→        .find_blob(entry.id())
102→        .map_err(|e| format!("Failed to read blob: {}", e))?;
103→
104→    std::str::from_utf8(blob.content())
105→        .map(|s| s.to_string())
106→        .map_err(|e| format!("Invalid UTF-8: {}", e))
107→}
