177→#[derive(serde::Serialize)]
178→struct FileDiff {
179→    path: String,
180→    status: String, // "added", "modified", "deleted"
181→    hunks: Vec<DiffHunk>,
182→}
183→
184→#[derive(serde::Serialize)]
185→struct DiffHunk {
186→    header: String,
187→    lines: Vec<DiffLine>,
188→}
189→
190→#[derive(serde::Serialize)]
191→struct DiffLine {
192→    kind: String, // "add", "delete", "context"
193→    content: String,
194→    old_lineno: Option<u32>,
195→    new_lineno: Option<u32>,
196→}
197→
198→/// Convert a git2::Diff into our FileDiff structs
199→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
200→    let mut files: Vec<FileDiff> = Vec::new();
201→
202→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
203→        let path = delta
204→            .new_file()
205→            .path()
206→            .or_else(|| delta.old_file().path())
207→            .map(|p| p.to_string_lossy().to_string())
208→            .unwrap_or_default();
209→
210→        let status = match delta.status() {
211→            git2::Delta::Added => "added",
212→            git2::Delta::Deleted => "deleted",
213→            _ => "modified",
214→        };
215→
216→        // Ensure we have a FileDiff entry for this path
217→        if files.last().map_or(true, |f| f.path != path) {
218→            files.push(FileDiff {
219→                path: path.clone(),
220→                status: status.to_string(),
221→                hunks: Vec::new(),
222→            });
223→        }
224→
225→        let file = files.last_mut().unwrap();
226→
227→        // New hunk
228→        if let Some(h) = hunk {
229→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
230→            if file.hunks.last().map_or(true, |last| last.header != header) {
231→                file.hunks.push(DiffHunk {
232→                    header,
233→                    lines: Vec::new(),
234→                });
235→            }
236→        }
237→
238→        // Diff line
239→        if let Some(current_hunk) = file.hunks.last_mut() {
240→            let kind = match line.origin() {
241→                '+' => "add",
242→                '-' => "delete",
243→                ' ' => "context",
244→                _ => return true,
245→            };
246→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
247→            current_hunk.lines.push(DiffLine {
248→                kind: kind.to_string(),
249→                content,
250→                old_lineno: line.old_lineno(),
251→                new_lineno: line.new_lineno(),
252→            });
253→        }
254→
255→        true
256→    })
257→    .map_err(|e| format!("Failed to print diff: {}", e))?;
258→
259→    Ok(files)
260→}
261→
262→#[tauri::command]
263→fn get_checkpoint_diff(
264→    repo_path: String,
265→    commit_sha: String,
266→) -> Result<Vec<FileDiff>, String> {
267→    if commit_sha.is_empty() {
268→        return Err("No commit SHA available for this checkpoint".to_string());
269→    }
270→
271→    let repo = git::open_repo(&repo_path)?;
272→    let oid = git2::Oid::from_str(&commit_sha)
273→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
274→    let commit = repo
275→        .find_commit(oid)
276→        .map_err(|e| format!("Commit not found: {}", e))?;
277→
278→    let tree = commit
279→        .tree()
280→        .map_err(|e| format!("Failed to get tree: {}", e))?;
281→
282→    // Diff against parent (or empty tree if no parent)
283→    let parent_tree = commit
284→        .parent(0)
285→        .ok()
286→        .and_then(|p| p.tree().ok());
287→
288→    let diff = repo
289→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
290→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
291→
292→    collect_diff_files(&diff)
293→}
