385→#[cfg_attr(mobile, tauri::mobile_entry_point)]
386→pub fn run() {
387→    tauri::Builder::default()
388→        .plugin(tauri_plugin_opener::init())
389→        .plugin(tauri_plugin_window_state::Builder::default().build())
390→        .manage(Mutex::new(AppState {
391→            pty_manager: pty::PtyManager::new(),
392→            watched_repos: HashSet::new(),
393→        }))
394→        .setup(|app| {
395→            // System tray
396→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
397→            use tauri::tray::TrayIconBuilder;
398→            use tauri::Manager;
399→
400→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
401→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
402→            let menu = MenuBuilder::new(app)
403→                .item(&show)
404→                .separator()
405→                .item(&quit)
406→                .build()?;
407→
408→            let _tray = TrayIconBuilder::new()
409→                .tooltip("Entire Desktop")
410→                .menu(&menu)
411→                .on_menu_event(move |app, event| {
412→                    match event.id().as_ref() {
413→                        "show" => {
414→                            if let Some(window) = app.get_webview_window("main") {
415→                                let _ = window.show();
416→                                let _ = window.set_focus();
417→                            }
418→                        }
419→                        "quit" => {
420→                            app.exit(0);
421→                        }
422→                        _ => {}
423→                    }
424→                })
425→                .on_tray_icon_event(|tray, event| {
426→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
427→                        let app = tray.app_handle();
428→                        if let Some(window) = app.get_webview_window("main") {
429→                            let _ = window.show();
430→                            let _ = window.set_focus();
431→                        }
432→                    }
433→                })
434→                .build(app)?;
435→
436→            Ok(())
437→        })
438→        .invoke_handler(tauri::generate_handler![
439→            list_repos,
440→            list_checkpoints,
441→            get_transcript,
442→            get_checkpoint_diff,
443→            get_branch_diff,
444→            list_sessions,
445→            spawn_agent,
446→            pty_input,
447→            pty_resize,
448→            kill_pty,
449→            launch_ghostty_agent,
450→            list_trails,
451→            watch_repo,
452→        ])
453→        .run(tauri::generate_context!())
454→        .expect("error while running tauri application");
455→}
