 32→/// Find the git common dir (handles worktrees)
 33→fn git_common_dir(repo_path: &str) -> PathBuf {
 34→    let git_dir = Path::new(repo_path).join(".git");
 35→    if git_dir.is_file() {
 36→        // Worktree: .git is a file containing "gitdir: /path/to/worktree/git"
 37→        if let Ok(content) = fs::read_to_string(&git_dir) {
 38→            if let Some(gitdir) = content.strip_prefix("gitdir: ") {
 39→                let gitdir = gitdir.trim();
 40→                let gitdir_path = if Path::new(gitdir).is_absolute() {
 41→                    PathBuf::from(gitdir)
 42→                } else {
 43→                    Path::new(repo_path).join(gitdir)
 44→                };
 45→                // commondir file tells us where the shared git dir is
 46→                let commondir_file = gitdir_path.join("commondir");
 47→                if let Ok(commondir) = fs::read_to_string(&commondir_file) {
 48→                    let commondir = commondir.trim();
 49→                    if Path::new(commondir).is_absolute() {
 50→                        return PathBuf::from(commondir);
 51→                    } else {
 52→                        return gitdir_path.join(commondir);
 53→                    }
 54→                }
 55→                return gitdir_path;
 56→            }
 57→        }
 58→    }
 59→    git_dir
 60→}
 61→
 62→/// List active sessions from .git/entire-sessions/
 63→pub fn list_active_sessions(repo_path: &str) -> Result<Vec<SessionState>, String> {
 64→    let sessions_dir = git_common_dir(repo_path).join("entire-sessions");
 65→    if !sessions_dir.exists() {
 66→        return Ok(Vec::new());
 67→    }
 68→
 69→    let mut sessions = Vec::new();
 70→    let entries =
 71→        fs::read_dir(&sessions_dir).map_err(|e| format!("Failed to read sessions dir: {}", e))?;
 72→
 73→    for entry in entries {
 74→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
 75→        let path = entry.path();
 76→        if path.extension().map_or(false, |ext| ext == "json") {
 77→            if let Ok(content) = fs::read_to_string(&path) {
 78→                if let Ok(state) = serde_json::from_str::<SessionState>(&content) {
 79→                    sessions.push(state);
 80→                }
 81→            }
 82→        }
 83→    }
 84→
 85→    Ok(sessions)
 86→}
