 87→/// List all checkpoints from the entire/checkpoints/v1 branch
 88→pub fn list_checkpoints(
 89→    repo: &Repository,
 90→    filter_branch: &str,
 91→) -> Result<Vec<CheckpointSummary>, String> {
 92→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
 93→        Ok(b) => b,
 94→        Err(_) => return Ok(Vec::new()), // No checkpoints branch yet
 95→    };
 96→
 97→    let commit = branch_ref
 98→        .get()
 99→        .peel_to_commit()
100→        .map_err(|e| format!("Failed to get checkpoint commit: {}", e))?;
101→
102→    let tree = commit
103→        .tree()
104→        .map_err(|e| format!("Failed to get tree: {}", e))?;
105→
106→    let mut checkpoints = Vec::new();
107→
108→    // Walk the sharded directory structure: <id[:2]>/<id[2:]>/metadata.json
109→    tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
110→        let name = match entry.name() {
111→            Some(n) => n,
112→            None => return git2::TreeWalkResult::Ok,
113→        };
114→
115→        // Look for metadata.json at the checkpoint level (e.g., "a1/b2c3d4/metadata.json")
116→        if name == "metadata.json" && !dir.is_empty() {
117→            // dir looks like "a1/b2c3d4/" — that's 2 levels deep
118→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
119→            if parts.len() == 2 {
120→                // This is a root checkpoint metadata.json
121→                if let Ok(blob) = repo.find_blob(entry.id()) {
122→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
123→                        if let Ok(meta) = serde_json::from_str::<RawCheckpointMetadata>(content) {
124→                            let branch = meta.branch.clone().unwrap_or_default();
125→                            if filter_branch.is_empty() || branch == filter_branch {
126→                                let cp = build_checkpoint_summary(
127→                                    repo,
128→                                    &tree,
129→                                    dir,
130→                                    &meta,
131→                                );
132→                                if let Ok(cp) = cp {
133→                                    checkpoints.push(cp);
134→                                }
135→                            }
136→                        }
137→                    }
138→                }
139→            }
140→        }
141→
142→        git2::TreeWalkResult::Ok
143→    })
144→    .map_err(|e| format!("Tree walk error: {}", e))?;
145→
146→    // Sort by created_at descending
147→    checkpoints.sort_by(|a, b| b.created_at.cmp(&a.created_at));
148→
149→    Ok(checkpoints)
150→}
151→
152→fn build_checkpoint_summary(
153→    repo: &Repository,
154→    _tree: &git2::Tree,
155→    dir: &str,
156→    meta: &RawCheckpointMetadata,
157→) -> Result<CheckpointSummary, String> {
158→    let checkpoint_id = meta
159→        .checkpoint_id
160→        .clone()
161→        .unwrap_or_else(|| dir.replace('/', ""));
162→
163→    let mut sessions = Vec::new();
164→    let mut earliest_created_at: Option<String> = None;
165→    // Read session metadata from subdirectories (0/, 1/, etc.)
166→    if let Some(refs) = &meta.sessions {
167→        for (i, session_ref) in refs.iter().enumerate() {
168→            let session_dir = format!("{}{}/", dir, i);
169→            let session_meta_path = format!("{}metadata.json", session_dir);
170→
171→            // Try to read session metadata from the tree
172→            if let Ok(session_meta) = read_blob_from_tree(repo, &session_meta_path) {
173→                if let Ok(sm) = serde_json::from_str::<RawSessionMetadata>(&session_meta) {
174→                    // Track earliest created_at across sessions
175→                    if let Some(ref ca) = sm.created_at {
176→                        if earliest_created_at.as_ref().map_or(true, |e| ca < e) {
177→                            earliest_created_at = Some(ca.clone());
178→                        }
179→                    }
180→
181→                    // Count steps from transcript if available
182→                    let step_count = count_transcript_steps(repo, session_ref, &session_dir);
183→
184→                    sessions.push(SessionSummary {
185→                        session_id: sm.session_id.unwrap_or_default(),
186→                        agent: sm.agent.unwrap_or_else(|| "Unknown".to_string()),
187→                        model: sm.model,
188→                        step_count,
189→                        summary: sm.summary,
190→                        token_usage: sm.token_usage,
191→                        initial_attribution: sm.initial_attribution,
192→                    });
193→                }
194→            }
195→        }
196→    }
197→
198→    // Use checkpoint metadata fields first, fall back to session-derived values
199→    let created_at = meta
200→        .created_at
201→        .clone()
202→        .or(earliest_created_at)
203→        .unwrap_or_default();
204→
205→    let branch_name = meta.branch.clone().unwrap_or_default();
206→
207→    // Resolve commit_sha and commit_message from the branch's git history
208→    // The checkpoint corresponds to the most recent commit on the branch at created_at time
209→    let (commit_sha, commit_message) = meta
210→        .commit_sha
211→        .clone()
212→        .filter(|s| !s.is_empty())
213→        .map(|sha| {
214→            let msg = meta.commit_message.clone().unwrap_or_default();
215→            (sha, msg)
216→        })
217→        .unwrap_or_else(|| {
218→            resolve_commit_from_branch(repo, &branch_name, &created_at)
219→                .unwrap_or_default()
220→        });
221→
222→    Ok(CheckpointSummary {
223→        checkpoint_id,
224→        branch: branch_name,
225→        commit_sha,
226→        commit_message,
227→        files_touched: meta.files_touched.clone().unwrap_or_default(),
228→        sessions,
229→        token_usage: meta.token_usage.clone(),
230→        created_at,
231→    })
232→}
233→
234→/// Find the most recent commit on a branch at or before the given timestamp.
235→/// Returns (sha, message) or None if not found.
236→fn resolve_commit_from_branch(
237→    repo: &Repository,
238→    branch_name: &str,
239→    created_at: &str,
240→) -> Option<(String, String)> {
241→    if branch_name.is_empty() || created_at.is_empty() {
242→        return None;
243→    }
244→
245→    let branch = repo.find_branch(branch_name, git2::BranchType::Local).ok()?;
246→    let branch_commit = branch.get().peel_to_commit().ok()?;
247→
248→    // Parse the checkpoint created_at as a unix timestamp for comparison
249→    let checkpoint_ts = parse_iso_timestamp(created_at)?;
250→
251→    // Walk commits from branch HEAD backward
252→    let mut revwalk = repo.revwalk().ok()?;
253→    revwalk.push(branch_commit.id()).ok()?;
254→    revwalk.set_sorting(git2::Sort::TIME).ok()?;
255→
256→    for oid in revwalk {
257→        let oid = oid.ok()?;
258→        let commit = repo.find_commit(oid).ok()?;
259→        let commit_ts = commit.time().seconds();
260→
261→        // Find the first commit whose time is at or before the checkpoint
262→        if commit_ts <= checkpoint_ts {
263→            let sha = oid.to_string();
264→            let message = commit
265→                .summary()
266→                .unwrap_or("")
267→                .to_string();
